 1	import * as React from 'react';
 2	import { Button } from '@patternfly/react-core';
 3	import * as _ from 'lodash';
 4	import { useTranslation } from 'react-i18next';
 5	import {
 6	  AccessReviewResourceAttributes,
 7	  useAccessReview,
 8	} from '@openshift-console/dynamic-plugin-sdk';
 9	import { PipelineRunModel } from '../../models';
10	import { returnValidPipelineRunModel } from '../utils/pipeline-utils';
11	import { getLatestRun } from '../utils/pipeline-augment';
12	import { PipelineRunKind } from '../../types';
13	import {
14	  useGetActiveUser,
15	  usePipelineRunWithUserAnnotation,
16	} from '../hooks/hooks';
17	import { rerunPipelineAndStay } from '../utils/pipelines-actions';
18	
19	type TriggerLastRunButtonProps = {
20	  pipelineRuns: PipelineRunKind[];
21	  namespace: string;
22	  impersonate?;
23	};
24	
25	const TriggerLastRunButton: React.FC<TriggerLastRunButtonProps> = ({
26	  pipelineRuns,
27	  namespace,
28	  impersonate,
29	}) => {
30	  const { t } = useTranslation('plugin__pipelines-console-plugin');
31	  const currentUser = useGetActiveUser();
32	  const latestRun = usePipelineRunWithUserAnnotation(
33	    getLatestRun(pipelineRuns, 'startTimestamp'),
34	  );
35	  const pipelineRunModel = returnValidPipelineRunModel(latestRun);
36	  const {
37	    labelKey,
38	    callback,
39	    accessReview: utilityAccessReview,
40	  } = rerunPipelineAndStay(pipelineRunModel, latestRun, currentUser);
41	  const defaultAccessReview: AccessReviewResourceAttributes = {
42	    group: PipelineRunModel.apiGroup,
43	    resource: PipelineRunModel.plural,
44	    namespace,
45	    verb: 'create',
46	  };
47	  const accessReview = _.isEmpty(utilityAccessReview)
48	    ? defaultAccessReview
49	    : utilityAccessReview;
50	  const isAllowed = useAccessReview(accessReview, impersonate);
51	  return (
52	    isAllowed && (
53	      <Button
54	        variant="secondary"
55	        onClick={callback}
56	        isDisabled={pipelineRuns.length === 0 && !callback}
57	      >
58	        {t(labelKey)}
59	      </Button>
60	    )
61	  );
62	};
63	
64	export default TriggerLastRunButton;

